query.sparql:
SELECT DISTINCT ?answer WHERE {
  ?operation wdt:P31 wd:Q645883. # Find instances of military operations
  ?operation wdt:P710 wd:Q625657. # Link operations to the Australian Defence Force
  ?operation wdt:P710 ?answer. # Find participants in the operation
  ?answer wdt:P31 wd:Q127161923. # Ensure the participant is an animal
}

SELECT ?answer WHERE {
  ?answer wdt:P451 wd:Q4463198.
  ?answer wdt:P451 wd:Q4205826.
}

SELECT ?answer WHERE {
  VALUES ?founder { wd:Q20689208 wd:Q1739008 wd:Q15934341 wd:Q18653685 wd:Q18659347 }
  ?founder wdt:P463 ?organization.
  ?organization rdfs:label "National People's Congress"@en.
  BIND(?founder AS ?answer)
}

SELECT ?work WHERE {
  wd:Q115781 wdt:P800 ?work. # P800 = notable work
  ?work wdt:P921 ?topic. # P921 = main subject
  ?topic rdfs:label "middle school student"@en.
}

SELECT ?answer WHERE {  
  wd:Q312101 wdt:P800 ?answer.  
  FILTER(?answer != wd:Q11835640).  
}

SELECT DISTINCT ?state WHERE {
  wd:Q2926117 wdt:P19 ?place1.
  wd:Q87192979 wdt:P19 ?place2.
  ?place1 wdt:P131* ?state.
  ?place2 wdt:P131* ?state.
}

SELECT ?answer WHERE {
  wd:Q6711 wdt:P69 ?answer.
  ?answer wdt:P31 wd:Q3914. # Ensures the institution is a high school
}

SELECT (COUNT(?person) AS ?answer) WHERE {
  ?person wdt:P39 wd:Q1048744;  # Position held: General Secretary of the CPSU
          p:P39 ?statement.
  ?statement pq:P580 ?startTime.  # Start time qualifier
  FILTER(?startTime < "1964-10-14T00:00:00Z"^^xsd:dateTime)  # Before Brezhnev's start date
}

SELECT (COUNT(DISTINCT ?person) AS ?answer) WHERE {
  ?person p:P39 ?statement.
  ?statement ps:P39 wd:Q218295;
             pq:P580 ?startDate.
  FILTER(YEAR(?startDate) > 1990)
}

ASK WHERE {  
  wd:Q350568 ?property ?medal.  
  ?medal wdt:P31 wd:Q11286439. # Olympic medal  
  ?medal wdt:P1344 wd:Q181278. # 2020 Summer Olympics  
}

SELECT ?kobeEnd ?lebronStart WHERE {
  wd:Q25369 p:P54 ?kobeMembership.
  ?kobeMembership ps:P54 wd:Q121783;
                  pq:P582 ?kobeEnd.

  wd:Q36159 p:P54 ?lebronMembership.
  ?lebronMembership ps:P54 wd:Q121783;
                    pq:P580 ?lebronStart.

  FILTER(?kobeEnd < ?lebronStart)
}
